86: // GetKey creates a prefixed cache key and uses the internal `encoder` to encode the query into a string
87: func GetKey(namespace, prefix string, query interface{}) (string, error) {
88: 	keybuf := bytes.NewBuffer(nil)
89: 
90: 	encoder := &JSONEncoder{}
91: 
92: 	if err := encoder.Encode(keybuf, query); err != nil {
93: 		return "", err
94: 	}
95: 
96: 	key, err := SHA256KeyFunc(keybuf)
97: 	if err != nil {
98: 		return "", err
99: 	}
100: 
101: 	// The namespace is empty only when this function is used by the legacy caching module.
102: 	// This case can be removed when the legacy caching module is not being used anymore.
103: 	if namespace != "" {
104: 		return strings.Join([]string{namespace, prefix, key}, ":"), nil
105: 	}
106: 
107: 	return strings.Join([]string{prefix, key}, ":"), nil
108: }
