110: // SHA256KeyFunc copies the data from `r` into a sha256.Hash, and returns the encoded Sum.
111: func SHA256KeyFunc(r io.Reader) (string, error) {
112: 	hash := sha256.New()
113: 
114: 	// Read all data from the provided reader
115: 	if _, err := io.Copy(hash, r); err != nil {
116: 		return "", err
117: 	}
118: 
119: 	// Encode the written values to SHA256
120: 	return hex.EncodeToString(hash.Sum(nil)), nil
121: }
