176: // WithQueryDataCaching calls `f` and caches the returned value if `req` has not been cached already.
177: // Returns the cached value otherwise.
178: func (c *CachingServiceClient) WithQueryDataCaching(ctx context.Context, req *backend.QueryDataRequest, f func() (*backend.QueryDataResponse, error)) (*backend.QueryDataResponse, error) {
179: 	if c == nil || req == nil {
180: 		return f()
181: 	}
182: 
183: 	reqCtx := contexthandler.FromContext(ctx)
184: 
185: 	// time how long this request takes
186: 	start := time.Now()
187: 
188: 	// First look in the query cache if enabled
189: 	hit, cr, status := c.cachingService.HandleQueryRequest(ctx, req)
190: 
191: 	// record request duration if caching was used
192: 	if reqCtx != nil {
193: 		reqCtx.Resp.Header().Set(XCacheHeader, string(status))
194: 		defer func() {
195: 			QueryCachingRequestHistogram.With(prometheus.Labels{
196: 				"datasource_type": getDatasourceType(req.PluginContext),
197: 				"cache":           string(status),
198: 				"query_type":      getQueryType(reqCtx),
199: 			}).Observe(time.Since(start).Seconds())
200: 		}()
201: 	}
202: 
203: 	// Cache hit; return the response
204: 	if hit {
205: 		return cr.Response, nil
206: 	}
207: 
208: 	// Cache miss; do the actual queries
209: 	resp, err := f()
210: 	// Update the query cache with the result for this metrics request
211: 	if err == nil && cr.UpdateCacheFn != nil {
212: 		// If AWS async caching is not enabled, use the old code path
213: 		//nolint:staticcheck // not yet migrated to OpenFeature
214: 		if c.features == nil || !c.features.IsEnabled(ctx, featuremgmt.FlagAwsAsyncQueryCaching) {
215: 			cr.UpdateCacheFn(ctx, resp)
216: 		} else if reqCtx != nil {
217: 			// time how long shouldCacheQuery takes
218: 			startShouldCacheQuery := time.Now()
219: 			shouldCache := ShouldCacheQuery(resp)
220: 			ShouldCacheQueryHistogram.With(prometheus.Labels{
221: 				"datasource_type": req.PluginContext.DataSourceInstanceSettings.Type,
222: 				"cache":           string(status),
223: 				"shouldCache":     strconv.FormatBool(shouldCache),
224: 				"query_type":      getQueryType(reqCtx),
225: 			}).Observe(time.Since(startShouldCacheQuery).Seconds())
226: 
227: 			// If AWS async caching is enabled and resp is for a running async query, don't cache it
228: 			if shouldCache {
229: 				cr.UpdateCacheFn(ctx, resp)
230: 			}
231: 		}
232: 	}
233: 
234: 	return resp, err
235: }
