237: // WithCallResourceCaching calls `f` and caches the returned value if `req` has not been cached already.
238: // Returns the cached value otherwise.
239: func (c *CachingServiceClient) WithCallResourceCaching(ctx context.Context, req *backend.CallResourceRequest, sender backend.CallResourceResponseSender, f func(backend.CallResourceResponseSender) error) error {
240: 	if c == nil || req == nil {
241: 		return f(sender)
242: 	}
243: 
244: 	reqCtx := contexthandler.FromContext(ctx)
245: 
246: 	// time how long this request takes
247: 	start := time.Now()
248: 
249: 	// First look in the resource cache if enabled
250: 	hit, cr, status := c.cachingService.HandleResourceRequest(ctx, req)
251: 
252: 	if reqCtx != nil {
253: 		reqCtx.Resp.Header().Set(XCacheHeader, string(status))
254: 	}
255: 	// record request duration if caching was used
256: 	defer func() {
257: 		ResourceCachingRequestHistogram.With(prometheus.Labels{
258: 			"plugin_id": req.PluginContext.PluginID,
259: 			"cache":     string(status),
260: 		}).Observe(time.Since(start).Seconds())
261: 	}()
262: 
263: 	// Cache hit; send the response and return
264: 	if hit {
265: 		return sender.Send(cr.Response)
266: 	}
267: 
268: 	// Cache miss; do the actual request
269: 	// If there is no update cache func, just pass in the original sender
270: 	if cr.UpdateCacheFn == nil {
271: 		return f(sender)
272: 	}
273: 	// Otherwise, intercept the responses in a wrapped sender so we can cache them first
274: 	cacheSender := backend.CallResourceResponseSenderFunc(func(res *backend.CallResourceResponse) error {
275: 		cr.UpdateCacheFn(ctx, res)
276: 		return sender.Send(res)
277: 	})
278: 
279: 	return f(cacheSender)
280: }
