{"content":"1: package remotecache
2: 
3: import (
4: 	"context"
5: 	"errors"
6: 	"time"
7: 
8: 	"github.com/grafana/grafana/pkg/infra/db"
9: 	"github.com/grafana/grafana/pkg/infra/usagestats"
10: 	"github.com/grafana/grafana/pkg/registry"
11: 	"github.com/grafana/grafana/pkg/services/secrets"
12: 	"github.com/grafana/grafana/pkg/setting"
13: )
14: 
15: var (
16: 	// ErrCacheItemNotFound is returned if cache does not exist
17: 	ErrCacheItemNotFound = errors.New("cache item not found")
18: 
19: 	// ErrInvalidCacheType is returned if the type is invalid
20: 	ErrInvalidCacheType = errors.New("invalid remote cache name")
21: 
22: 	defaultMaxCacheExpiration = time.Hour * 24
23: )
24: 
25: const (
26: 	ServiceName = "RemoteCache"
27: )
28: 
29: func ProvideService(cfg *setting.Cfg, sqlStore db.DB, usageStats usagestats.Service,
30: 	secretsService secrets.Service) (*RemoteCache, error) {
31: 	client, err := createClient(cfg.RemoteCacheOptions, sqlStore, secretsService)
32: 	if err != nil {
33: 		return nil, err
34: 	}
35: 	s := &RemoteCache{
36: 		SQLStore: sqlStore,
37: 		Cfg:      cfg,
38: 		client:   client,
39: 	}
40: 
41: 	usageStats.RegisterMetricsFunc(s.getUsageStats)
42: 
43: 	return s, nil
44: }
45: 
46: func (ds *RemoteCache) getUsageStats(ctx context.Context) (map[string]any, error) {
47: 	stats := map[string]any{}
48: 	stats["stats.remote_cache."+ds.Cfg.RemoteCacheOptions.Name+".count"] = 1
49: 	encryptVal := 0
50: 	if ds.Cfg.RemoteCacheOptions.Encryption {
51: 		encryptVal = 1
52: 	}
53: 
54: 	stats["stats.remote_cache.encrypt_enabled.count"] = encryptVal
55: 
56: 	return stats, nil
57: }
58: 
59: // CacheStorage allows the caller to set, get and delete items in the cache.
60: // Cached items are stored as byte arrays and marshalled using "encoding/gob"
61: // so any struct added to the cache needs to be registered with `remotecache.Register`
62: // ex `remotecache.Register(CacheableStruct{})`
63: type CacheStorage interface {
64: 	// Get gets the cache value as an byte array
65: 	Get(ctx context.Context, key string) ([]byte, error)
66: 
67: 	// Set saves the value as an byte array. if `expire` is set to zero it will default to 24h
68: 	Set(ctx context.Context, key string, value []byte, expire time.Duration) error
69: 
70: 	// Delete object from cache
71: 	Delete(ctx context.Context, key string) error
72: }
73: 
74: // RemoteCache allows Grafana to cache data outside its own process
75: type RemoteCache struct {
76: 	client   CacheStorage
77: 	SQLStore db.DB
78: 	Cfg      *setting.Cfg
79: }
80: 
81: // Get returns the cached value as an byte array
82: func (ds *RemoteCache) Get(ctx context.Context, key string) ([]byte, error) {
83: 	return ds.client.Get(ctx, key)
84: }
85: 
86: // Set stored the byte array in the cache
87: func (ds *RemoteCache) Set(ctx context.Context, key string, value []byte, expire time.Duration) error {
88: 	if expire == 0 {
89: 		expire = defaultMaxCacheExpiration
90: 	}
91: 
92: 	return ds.client.Set(ctx, key, value, expire)
93: }
94: 
95: // Delete object from cache
96: func (ds *RemoteCache) Delete(ctx context.Context, key string) error {
97: 	return ds.client.Delete(ctx, key)
98: }
99: 
100: // Run starts the backend processes for cache clients.
101: func (ds *RemoteCache) Run(ctx context.Context) error {
102: 	// create new interface if more clients need GC jobs
103: 	backgroundjob, ok := ds.client.(registry.BackgroundService)
104: 	if ok {
105: 		return backgroundjob.Run(ctx)
106: 	}
107: 
108: 	<-ctx.Done()
109: 	return ctx.Err()
110: }
111: 
112: func createClient(opts *setting.RemoteCacheSettings, sqlstore db.DB, secretsService secrets.Service) (cache CacheStorage, err error) {
113: 	switch opts.Name {
114: 	case redisCacheType:
115: 		cache, err = newRedisStorage(opts)
116: 	case memcachedCacheType:
117: 		cache = newMemcachedStorage(opts)
118: 	case databaseCacheType:
119: 		cache = newDatabaseCache(sqlstore)
120: 	default:
121: 		return nil, ErrInvalidCacheType
122: 	}
123: 	if err != nil {
124: 		return cache, err
125: 	}
126: 	if opts.Prefix != "" {
127: 		cache = &prefixCacheStorage{cache: cache, prefix: opts.Prefix}
128: 	}
129: 
130: 	if opts.Encryption {
131: 		cache = &encryptedCacheStorage{cache: cache, secretsService: secretsService}
132: 	}
133: 	return cache, nil
134: }
135: 
136: type encryptedCacheStorage struct {
137: 	cache          CacheStorage
138: 	secretsService encryptionService
139: }
140: 
141: type encryptionService interface {
142: 	Encrypt(ctx context.Context, payload []byte, opt secrets.EncryptionOptions) ([]byte, error)
143: 	Decrypt(ctx context.Context, payload []byte) ([]byte, error)
144: }
145: 
146: func (pcs *encryptedCacheStorage) Get(ctx context.Context, key string) ([]byte, error) {
147: 	data, err := pcs.cache.Get(ctx, key)
148: 	if err != nil {
149: 		return nil, err
150: 	}
151: 
152: 	return pcs.secretsService.Decrypt(ctx, data)
153: }
154: func (pcs *encryptedCacheStorage) Set(ctx context.Context, key string, value []byte, expire time.Duration) error {
155: 	encrypted, err := pcs.secretsService.Encrypt(ctx, value, secrets.WithoutScope())
156: 	if err != nil {
157: 		return err
158: 	}
159: 
160: 	return pcs.cache.Set(ctx, key, encrypted, expire)
161: }
162: func (pcs *encryptedCacheStorage) Delete(ctx context.Context, key string) error {
163: 	return pcs.cache.Delete(ctx, key)
164: }
165: 
166: type prefixCacheStorage struct {
167: 	cache  CacheStorage
168: 	prefix string
169: }
170: 
171: func (pcs *prefixCacheStorage) Get(ctx context.Context, key string) ([]byte, error) {
172: 	return pcs.cache.Get(ctx, pcs.prefix+key)
173: }
174: func (pcs *prefixCacheStorage) Set(ctx context.Context, key string, value []byte, expire time.Duration) error {
175: 	return pcs.cache.Set(ctx, pcs.prefix+key, value, expire)
176: }
177: func (pcs *prefixCacheStorage) Delete(ctx context.Context, key string) error {
178: 	return pcs.cache.Delete(ctx, pcs.prefix+key)
179: }
